const result = $input.first().json;

if (!result || result.valid !== true) {
  throw new Error('Invalid request signature');
}

const authHeader = $('Receive Delete Request').first().json.headers.authorization ?? '';
const token = authHeader.replace('Bearer ', '').trim();

return [{ json: { hmac_valid: true, token } }];

const session = $input.first().json;

if (!session || !session.user_id) {
  throw new Error('Invalid or expired token');
}

if (!session.user_active) {
  throw new Error('User account is inactive');
}

if (!session.client_active) {
  throw new Error('Client account is inactive');
}

if (session.is_caiac_staff !== true) {
  throw new Error('Insufficient permissions: is_caiac_staff required');
}

const clientUUID = $('Get Webhook Secret').first().json.id;
const body = $('Receive Delete Request').first().json.body;

return [{
  json: {
    user_id: session.user_id,
    is_caiac_staff: true,
    client_id: clientUUID,
    client_slug: body.client_id,
    filename: body.filename
  }
}];
